import{_ as t,o as e,c as a,a2 as i}from"./chunks/framework.Bix3-HpO.js";const u=JSON.parse('{"title":"Theme Customizations","description":"Akurai Theme Customizations","frontmatter":{"title":"Theme Customizations","description":"Akurai Theme Customizations","weight":120,"extra":{"order":120},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/akurai/customizations"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/akurai/customizations"}],["meta",{"property":"og:title","content":"Theme Customizations"}],["meta",{"property":"og:description","content":"Akurai Theme Customizations"}],["meta",{"name":"twitter:title","content":"Theme Customizations"}],["meta",{"name":"twitter:description","content":"Akurai Theme Customizations"}]]},"headers":[],"relativePath":"docs/akurai/customizations.md","filePath":"docs/akurai/customizations.md"}'),s={name:"docs/akurai/customizations.md"};function n(r,o,c,p,d,m){return e(),a("div",null,[...o[0]||(o[0]=[i('<h1 id="theme-customizations" tabindex="-1">Theme Customizations <a class="header-anchor" href="#theme-customizations" aria-label="Permalink to &quot;Theme Customizations&quot;">​</a></h1><p>Theme customizations are made through native WordPress Customizer. In admin dashboard visit <strong>Appearance</strong> → <strong>Customize</strong> select the options group you want to customize and make the required changes.</p><h2 id="customizer-options" tabindex="-1">Customizer Options <a class="header-anchor" href="#customizer-options" aria-label="Permalink to &quot;Customizer Options&quot;">​</a></h2><p>Below is the main WordPress Customizer view showing all the options you can customize.</p><p>Also you can find the customizer options and values for the <a href="https://demos.dinomatic.com/athens" target="_blank" rel="noreferrer">theme main demo</a>.</p><p><img src="https://media.dinomatic.com/images/docs/akurai/customizer/customizer.jpg" alt="Theme Customizations"></p><h3 id="site-identity" tabindex="-1">Site Identity <a class="header-anchor" href="#site-identity" aria-label="Permalink to &quot;Site Identity&quot;">​</a></h3><p>This is the standard Site Identity section where you can upload your logo and favicon, set site title and tagline.</p><p><img src="https://media.dinomatic.com/images/docs/akurai/customizer/site-identity.jpg" alt="customizer-site-identity"></p><h3 id="colors" tabindex="-1">Colors <a class="header-anchor" href="#colors" aria-label="Permalink to &quot;Colors&quot;">​</a></h3><p>Define main theme colors here.</p><p><img src="https://media.dinomatic.com/images/docs/akurai/customizer/colors.jpg" alt="customizer-color-options"></p><h3 id="header-options" tabindex="-1">Header Options <a class="header-anchor" href="#header-options" aria-label="Permalink to &quot;Header Options&quot;">​</a></h3><p>Header options such as colors, navigation menu styles, header layout and positioning.</p><p><code>💁 since version 3.0.0</code> you can add a search form to the header.</p><p><img src="https://media.dinomatic.com/images/docs/akurai/customizer/header-options.jpg" alt="customizer-header-options"></p><h3 id="footer-options" tabindex="-1">Footer Options <a class="header-anchor" href="#footer-options" aria-label="Permalink to &quot;Footer Options&quot;">​</a></h3><p>Footer colors, footer navigation, gambling logos and copyright text. If you&#39;re using year in your copyright text, you can replace it with <code>_current_year_</code> and it will display the current year.</p><p><img src="https://media.dinomatic.com/images/docs/akurai/customizer/footer-options.jpg" alt="customizer-footer-options"></p><h3 id="font-options" tabindex="-1">Font Options <a class="header-anchor" href="#font-options" aria-label="Permalink to &quot;Font Options&quot;">​</a></h3><p>Website font family. You can choose a system default font or one from <a href="https://fonts.google.com" target="_blank" rel="noreferrer">Google Fonts</a> or <a href="https://fonts.bunny.net" target="_blank" rel="noreferrer">Bunny Fonts</a>.</p><h3 id="section-options" tabindex="-1">Section Options <a class="header-anchor" href="#section-options" aria-label="Permalink to &quot;Section Options&quot;">​</a></h3><p>Here you define what Akurai sections look like and it&#39;ll affect almost everything including blocks and shortcodes.</p><p><img src="https://media.dinomatic.com/images/docs/akurai/customizer/section-options.jpg" alt="customizer-section-options"></p><h3 id="link-options" tabindex="-1">Link Options <a class="header-anchor" href="#link-options" aria-label="Permalink to &quot;Link Options&quot;">​</a></h3><p>Define link colors and <code>rel</code> and <code>target</code> attributes.</p><p><img src="https://media.dinomatic.com/images/docs/akurai/customizer/link-options.jpg" alt="customizer-link-options"></p><h3 id="button-options" tabindex="-1">Button Options <a class="header-anchor" href="#button-options" aria-label="Permalink to &quot;Button Options&quot;">​</a></h3><p>Theme button options such as colors, font styles, as well as hover effects and other styles.</p><p><img src="https://media.dinomatic.com/images/docs/akurai/customizer/button-options.jpg" alt="customizer-button-options"></p><h3 id="review-options" tabindex="-1">Review Options <a class="header-anchor" href="#review-options" aria-label="Permalink to &quot;Review Options&quot;">​</a></h3><p>A plenty of options related to reviews and review pages. You can specify text contents used on these pages, choose Hero layouts for default and banner templates, whether to display a featured image on review pages, as well as specify review logo sizes for better performance and rendering, etc.</p><p>You can also enable/disable review/rating snippets (schema.org) markup for review pages, and adjust review author options.</p><p><img src="https://media.dinomatic.com/images/docs/akurai/customizer/review-options-1.jpg" alt="customizer-review-options"><img src="https://media.dinomatic.com/images/docs/akurai/customizer/review-options-2.jpg" alt="customizer-review-options-2"></p><h3 id="posts-options" tabindex="-1">Posts Options <a class="header-anchor" href="#posts-options" aria-label="Permalink to &quot;Posts Options&quot;">​</a></h3><p>Several options related to posts, blog and archive pages. First of all, you can disable featured images on single post pages. You can disable post meta data above the content (author, date) and below it (categories, tags, comments count) - this will affect not only single posts, but also blog page and archive pages such as category and tag pages.</p><p>You can also customize the layout of the blog page, by choosing to display it in a 2 column grid.</p><p><code>💁 since version 2.2.2</code> you can change the posts navigation type on archive pages: previous/next links or page numbers.</p><p><code>💁 since version 3.0.0</code> you can change the posts header style by choosing whether or not to display a hero on top og the page.</p><p><img src="https://media.dinomatic.com/images/docs/akurai/customizer/posts-options.jpg" alt="customizer-posts-options"></p><h3 id="shortcode-options" tabindex="-1">Shortcode Options <a class="header-anchor" href="#shortcode-options" aria-label="Permalink to &quot;Shortcode Options&quot;">​</a></h3><p>Specify various block/shortcode options such as anchor texts and the number of review stars, etc.</p><p><img src="https://media.dinomatic.com/images/docs/akurai/customizer/block-options.jpg" alt="customizer-block-options"></p><h3 id="breadcrumbs-options" tabindex="-1">Breadcrumbs Options <a class="header-anchor" href="#breadcrumbs-options" aria-label="Permalink to &quot;Breadcrumbs Options&quot;">​</a></h3><p>Read more about breadcrumbs <a href="/docs/akurai/breadcrumbs">here</a></p>',45)])])}const l=t(s,[["render",n]]);export{u as __pageData,l as default};
